_FADE_MS = 3000  # 渐显渐隐时长（毫秒）
_REF_WIDTH = 1920
_REF_HEIGHT = 1080
_SIZE_PRESETS = {
    1920: (300, 80),   # 1080p
    3840: (600, 160),  # 4K
}


def _coord_pattern():
    return re.compile(r'(?<!\d)(\d+\.?\d*)\s+(\d+\.?\d*)\s')


def _calc_position(alignment, margin, img_w, img_h, playres_x, playres_y):
    if alignment == "top-left":
        return margin, margin
    elif alignment == "top-right":
        return playres_x - img_w - margin, margin
    elif alignment == "bottom-left":
        return margin, playres_y - img_h - margin
    elif alignment == "bottom-right":
        return playres_x - img_w - margin, playres_y - img_h - margin
    return margin, margin


def _time_fmt(seconds):
    if seconds < 0:
        seconds = 0
    total = int(seconds)
    h = total // 3600
    m = (total % 3600) // 60
    s = seconds - h * 3600 - m * 60
    return f"{h}:{m:02d}:{s:05.2f}"


def _parse_time(time_str):
    parts = time_str.strip().split(":")
    if len(parts) == 3:
        h, m, s = int(parts[0]), int(parts[1]), float(parts[2])
        return h * 3600 + m * 60 + s
    return 0


def _parse_dialogue_line(line):
    """
    安全解析 ASS Dialogue 行。
    找到第9个逗号（Effect字段后的分隔符），保留 double-comma 格式。
    返回 (header_before_time, header_after_time, text_content) 或 None。
    header 格式: "Dialogue: Layer," ... "0,0,0,," (最后有,,)
    """
    idx = -1
    count = 0
    for i, ch in enumerate(line):
        if ch == ',':
            count += 1
            if count == 9:
                idx = i
                break
    if idx < 0:
        return None
    # header = "Dialogue: Layer,Start,End,Style,Name,ML,MR,MV,"
    header = line[:idx + 1]  # 包含第9个逗号
    text = line[idx + 1:]    # ",{...}" 或 "{...}" (Effect + Text)
    # text 以 Effect 字段开头，后面是 ",," 再接 Text
    # 但更简单的方式：直接替换 header 中的时间
    # header = "Dialogue: Layer,Start,End,Style,Name,ML,MR,MV,"
    # 我们需要修改 Start 和 End
    h_parts = header.rstrip(",").split(",")
    return h_parts, text


def _rebuild_dialogue(h_parts, text):
    """用修改后的 header parts 和原始 text 重建 Dialogue 行"""
    # h_parts 最后一个元素是 Effect 字段（通常为空字符串）
    # ASS 格式要求 Effect 和 Text 之间有逗号分隔
    # 如果 Effect 为空，text 以 "{\..." 开头，需要确保 ",," 格式
    base = ",".join(h_parts)
    if text and not text.startswith(","):
        return base + ",," + text
    return base + "," + text


def load_ass_watermark(path=None):
    if path and Path(path).is_file():
        src_lines = []
        with open(path, "r", encoding="utf-8") as f:
            for raw_line in f:
                line = raw_line.rstrip("\n\r")
                if line.startswith("Dialogue:"):
                    src_lines.append(line)
    else:
        src_lines = list(_EMBEDDED_DIALOGUES)

    lines = []
    xs, ys = [], []
    pat = _coord_pattern()

    for line in src_lines:
        lines.append(line)
        parsed = _parse_dialogue_line(line)
        if not parsed:
            continue
        _, text = parsed
        for m in pat.finditer(text):
            x, y = float(m.group(1)), float(m.group(2))
            if x <= _REF_WIDTH and y <= _REF_HEIGHT:
                xs.append(x)
                ys.append(y)

    if not xs:
        return [], 0, 0, 0, 0

    orig_w = max(xs) - min(xs)
    orig_h = max(ys) - min(ys)
    return lines, orig_w, orig_h, min(xs), min(ys)
def _resolve_target_size(playres_x, playres_y):
    if playres_x in _SIZE_PRESETS:
        return _SIZE_PRESETS[playres_x]
    scale = playres_x / 1920
    return (int(300 * scale), int(80 * scale))


def generate_watermark_dialogues(
    playres_x=1920, playres_y=1080,
    alignment="top-right", margin=10,
    start_sec=900, duration_sec=30,
    ass_path="", top_bar=0,
):
    """
    生成水印 Dialogue 行（单次出现）。
    - start_sec: 水印开始出现的时间（秒），默认 900 = 15:00
    - duration_sec: 持续秒数
    """
    src_path = ass_path if ass_path else None
    dialogues, orig_w, orig_h, min_x, min_y = load_ass_watermark(src_path)
    if not dialogues or orig_w == 0 or orig_h == 0:
        return []

    target_w, target_h = _resolve_target_size(playres_x, playres_y)

    # X 位置：右对齐，右边距固定
    pos_x = playres_x - target_w - margin

    # Y 位置：跟随字幕组信息的垂直策略
    top_bar = max(0, int(top_bar))
    if top_bar >= target_h:
        # 黑边够高 → 黑边内垂直居中
        pos_y = (top_bar - target_h) // 2
    elif top_bar > 0:
        # 黑边不够高 → 贴黑边下方
        pos_y = top_bar
    else:
        # 无黑边 → 贴画面顶部
        pos_y = margin
    scale_x = target_w / orig_w
    scale_y = target_h / orig_h

    end_sec = start_sec + duration_sec
    pat = _coord_pattern()
    result = []

    for line in dialogues:
        parsed = _parse_dialogue_line(line)
        if not parsed:
            result.append(line + "\n")
            continue

        h_parts, text = parsed

        # 替换时间字段
        # h_parts[1] = Start, h_parts[2] = End
        h_parts[1] = _time_fmt(start_sec)
        h_parts[2] = _time_fmt(end_sec)

        # 缩放 + 偏移 text 中的坐标
        def _transform(m):
            x, y = float(m.group(1)), float(m.group(2))
            if x > _REF_WIDTH or y > _REF_HEIGHT:
                return m.group(0)
            # 先归一化到 (0,0) 起点，再缩放，再偏移到目标位置
            nx = (x - min_x) * scale_x + pos_x
            ny = (y - min_y) * scale_y + pos_y
            return f"{nx:.1f} {ny:.1f} "

        new_text = pat.sub(_transform, text)
        # 注入 \fad 渐显渐隐标签到 override 块中
        fad_tag = r"\fad(" + str(_FADE_MS) + r"," + str(_FADE_MS) + r")"
        if new_text.lstrip().startswith("{") and fad_tag not in new_text:
            new_text = new_text.replace("{", "{" + fad_tag, 1)
        result.append(_rebuild_dialogue(h_parts, new_text) + "\n")

    return result
